commit 7eff0bbed8ebae2a77f383318d172b27727b5e60
Author: Felix Abecassis <fabecassis@nvidia.com>
Date:   Tue Apr 28 15:08:01 2026 -0700

    Add support for PID namespace

    Signed-off-by: Felix Abecassis <fabecassis@nvidia.com>
---
 bin/enroot-nsenter.c | 192 ++++++++++++++++++++++++++++++++++++++++++++++++---
 conf/enroot.conf.in  |   3 +
 doc/cmd/start.md     |   5 +-
 enroot.in            |   8 +++
 src/runtime.sh       |  14 ++--
 5 files changed, 208 insertions(+), 14 deletions(-)

diff --git a/bin/enroot-nsenter.c b/bin/enroot-nsenter.c
index ac713c8..b76e0b3 100644
--- a/bin/enroot-nsenter.c
+++ b/bin/enroot-nsenter.c
@@ -32,7 +32,9 @@
 #include <linux/filter.h>
 #include <linux/seccomp.h>
 #include <net/if.h>
+#include <poll.h>
 #include <sched.h>
+#include <signal.h>
 #include <stddef.h>
 #include <stdint.h>
 #include <string.h>
@@ -42,6 +44,7 @@
 #include <sys/stat.h>
 #include <sys/syscall.h>
 #include <sys/types.h>
+#include <sys/wait.h>
 #include <unistd.h>

 #include <bsd/inttypes.h>
@@ -62,6 +65,13 @@
 #ifndef CLONE_NEWCGROUP
 # define CLONE_NEWCGROUP 0x02000000
 #endif
+#ifndef SYS_pidfd_open
+# ifdef __NR_pidfd_open
+#  define SYS_pidfd_open __NR_pidfd_open
+# else
+#  define SYS_pidfd_open 434
+# endif
+#endif

 #ifndef SECCOMP_FILTER_FLAG_SPEC_ALLOW
 # define SECCOMP_FILTER_FLAG_SPEC_ALLOW 4
@@ -99,6 +109,8 @@
 #define AUDIT_ARCH_AARCH64 (EM_AARCH64|__AUDIT_ARCH_64BIT|__AUDIT_ARCH_LE)
 #endif

+static volatile sig_atomic_t child_pid;
+
 static struct sock_filter filter[] = {
         /* Check for the syscall architecture (x86_64 and aarch64 ABIs). */
         BPF_STMT(BPF_LD|BPF_W|BPF_ABS, offsetof(struct seccomp_data, arch)),
@@ -183,7 +195,141 @@ loopback_up(void)
 }

 static void
-create_namespaces(bool user, bool mount, bool network, bool ipc, bool uts, bool remap_root)
+forward_signal(int sig)
+{
+        if (child_pid > 0)
+                (void)kill((pid_t)child_pid, sig);
+}
+
+static int
+pidfd_open(pid_t pid)
+{
+        return ((int)syscall(SYS_pidfd_open, pid, 0));
+}
+
+static void
+wait_child(pid_t pid)
+{
+        sigset_t sigset;
+        int status, sig;
+        pid_t ret;
+
+        for (;;) {
+                do {
+                        ret = waitpid(pid, &status, WUNTRACED);
+                } while (ret < 0 && errno == EINTR);
+
+                if (ret < 0)
+                        err(EXIT_FAILURE, "failed to wait for child process");
+                if (!WIFSTOPPED(status))
+                        break;
+
+                (void)kill(getpid(), SIGSTOP);
+                (void)kill(pid, SIGCONT);
+        }
+
+        if (WIFEXITED(status))
+                exit(WEXITSTATUS(status));
+        if (WIFSIGNALED(status)) {
+                sig = WTERMSIG(status);
+                if (sig != SIGKILL && signal(sig, SIG_DFL) == SIG_ERR)
+                        err(EXIT_FAILURE, "failed to reset signal handler");
+                if (sigemptyset(&sigset) < 0)
+                        err(EXIT_FAILURE, "failed to initialize signal mask");
+                if (sigaddset(&sigset, sig) < 0)
+                        err(EXIT_FAILURE, "failed to update signal mask");
+                if (sigprocmask(SIG_UNBLOCK, &sigset, NULL) < 0)
+                        err(EXIT_FAILURE, "failed to unblock signal");
+                (void)kill(getpid(), sig);
+                exit(128 + sig);
+        }
+        errx(EXIT_FAILURE, "child process terminated unexpectedly");
+}
+
+static void
+fork_child(void)
+{
+        char buf[32];
+        sigset_t oldsigset;
+        struct sigaction sa;
+        struct pollfd pfd;
+        ssize_t n;
+        size_t len;
+        int fds[2], parentfd;
+        pid_t pid;
+
+        if (pipe(fds) < 0)
+                err(EXIT_FAILURE, "failed to create pipe");
+        if ((parentfd = pidfd_open(getpid())) < 0)
+                err(EXIT_FAILURE, "failed to open pidfd");
+
+        memset(&sa, 0, sizeof(sa));
+        sa.sa_handler = forward_signal;
+        sa.sa_flags = SA_RESTART;
+        if (sigemptyset(&sa.sa_mask) < 0)
+                err(EXIT_FAILURE, "failed to initialize signal mask");
+        if (sigaction(SIGTERM, &sa, NULL) < 0)
+                err(EXIT_FAILURE, "failed to set signal handler");
+        if (sigaction(SIGINT, &sa, NULL) < 0)
+                err(EXIT_FAILURE, "failed to set signal handler");
+        if (sigprocmask(SIG_SETMASK, NULL, &oldsigset) < 0)
+                err(EXIT_FAILURE, "failed to get signal mask");
+
+        switch ((pid = fork())) {
+        case -1:
+                err(EXIT_FAILURE, "failed to fork");
+        case 0:
+                child_pid = 0;
+                if (sigprocmask(SIG_SETMASK, &oldsigset, NULL) < 0)
+                        err(EXIT_FAILURE, "failed to restore signal mask");
+                if (prctl(PR_SET_PDEATHSIG, SIGKILL, 0, 0, 0) < 0)
+                        err(EXIT_FAILURE, "failed to set parent death signal");
+                pfd = (struct pollfd){.fd = parentfd, .events = POLLIN};
+                switch (poll(&pfd, 1, 0)) {
+                case -1:
+                        err(EXIT_FAILURE, "failed to poll pidfd");
+                case 0:
+                        break;
+                default:
+                        exit(EXIT_FAILURE);
+                }
+                if (close(parentfd) < 0)
+                        err(EXIT_FAILURE, "failed to close pidfd");
+                if (close(fds[1]) < 0)
+                        err(EXIT_FAILURE, "failed to close pipe");
+                if ((n = read(fds[0], buf, sizeof(buf) - 1)) < 0)
+                        err(EXIT_FAILURE, "failed to read pipe");
+                buf[n] = '\0';
+                if (n > 0 && setenv("ENROOT_NSENTER_PID", buf, 1) < 0)
+                        err(EXIT_FAILURE, "failed to set environment");
+                if (close(fds[0]) < 0)
+                        err(EXIT_FAILURE, "failed to close pipe");
+                return;
+        default:
+                child_pid = pid;
+                if (close(parentfd) < 0)
+                        err(EXIT_FAILURE, "failed to close pidfd");
+                if (close(fds[0]) < 0)
+                        err(EXIT_FAILURE, "failed to close pipe");
+                len = (size_t)snprintf(buf, sizeof(buf), "%jd", (intmax_t)pid);
+                if (len >= sizeof(buf)) {
+                        errno = EOVERFLOW;
+                        err(EXIT_FAILURE, "failed to format child PID");
+                }
+                n = write(fds[1], buf, len);
+                if (n < 0 || (size_t)n != len) {
+                        if (n >= 0)
+                                errno = EIO;
+                        err(EXIT_FAILURE, "failed to write pipe");
+                }
+                if (close(fds[1]) < 0)
+                        err(EXIT_FAILURE, "failed to close pipe");
+                wait_child(pid);
+        }
+}
+
+static void
+create_namespaces(bool user, bool pid, bool mount, bool network, bool ipc, bool uts, bool remap_root)
 {
         if (user) {
                 if (!remap_root && prctl(PR_CAP_AMBIENT, PR_CAP_AMBIENT_IS_SET, 0, 0, 0) < 0 && errno == EINVAL)
@@ -193,6 +339,11 @@ create_namespaces(bool user, bool mount, bool network, bool ipc, bool uts, bool
                 if (!remap_root)
                         raise_capabilities();
         }
+        if (pid) {
+                if (unshare(CLONE_NEWPID) < 0)
+                        err(EXIT_FAILURE, "failed to create PID namespace");
+                fork_child();
+        }
         if (mount) {
                 if (unshare(CLONE_NEWNS) < 0)
                         err(EXIT_FAILURE, "failed to create mount namespace");
@@ -261,14 +412,16 @@ do_setns(int fd, int nstype, const char *nsstr)
 }

 static void
-join_namespaces(pid_t pid, bool user, bool mount, bool network, bool ipc, bool uts)
+join_namespaces(pid_t pid, bool user, bool pidns, bool mount, bool network, bool ipc, bool uts)
 {
-        int user_fd = -1, mount_fd = -1, network_fd = -1;
+        int user_fd = -1, pid_fd = -1, mount_fd = -1, network_fd = -1;
         int ipc_fd = -1, uts_fd = -1, cgroup_fd = -1;

         /* Open namespace fds first since joining the mount namespace can change /proc visibility. */
         if (user && (user_fd = open_namespace(pid, "user")) < 0)
                 err(EXIT_FAILURE, "failed to open user namespace");
+        if (pidns && (pid_fd = open_namespace(pid, "pid")) < 0)
+                err(EXIT_FAILURE, "failed to open PID namespace");
         if (mount && (mount_fd = open_namespace(pid, "mnt")) < 0)
                 err(EXIT_FAILURE, "failed to open mount namespace");
         if (network && (network_fd = open_namespace(pid, "net")) < 0)
@@ -284,6 +437,15 @@ join_namespaces(pid_t pid, bool user, bool mount, bool network, bool ipc, bool u
                 if (do_setns(user_fd, CLONE_NEWUSER, "user") < 0)
                         err(EXIT_FAILURE, "failed to join user namespace");
         }
+        if (pidns) {
+                switch (do_setns(pid_fd, CLONE_NEWPID, "pid")) {
+                case -1:
+                        err(EXIT_FAILURE, "failed to join PID namespace");
+                case 1:
+                        fork_child();
+                        break;
+                }
+        }
         if (mount) {
                 if (do_setns(mount_fd, CLONE_NEWNS, "mnt") < 0)
                         err(EXIT_FAILURE, "failed to join mount namespace");
@@ -336,10 +498,10 @@ seccomp_set_filter(void)
 int
 main(int argc, char *argv[])
 {
-        bool user = false, mount = false, network = false, ipc = false, uts = false, remap_root = false;
+        bool user = false, pid = false, mount = false, network = false, ipc = false, uts = false, remap_root = false;
         char *envfile = NULL, *workdir = NULL;
         pid_t target = -1;
-        int e;
+        int e, workdir_fd = -1;

         for (;;) {
                 if (argc >= 3 && !strcmp(argv[1], "--target")) {
@@ -369,6 +531,11 @@ main(int argc, char *argv[])
                         SHIFT_ARGS(1);
                         continue;
                 }
+                if (argc >= 2 && !strcmp(argv[1], "--pid")) {
+                        pid = true;
+                        SHIFT_ARGS(1);
+                        continue;
+                }
                 if (argc >= 2 && !strcmp(argv[1], "--net")) {
                         network = true;
                         SHIFT_ARGS(1);
@@ -392,14 +559,19 @@ main(int argc, char *argv[])
                 break;
         }
         if (argc < 2) {
-                printf("Usage: %s [--target PID] [--user] [--mount] [--net] [--ipc] [--uts] [--remap-root] [--envfile FILE] [--workdir DIR] COMMAND [ARG...]\n", argv[0]);
+                printf("Usage: %s [--target PID] [--user] [--mount] [--pid] [--net] [--ipc] [--uts] [--remap-root] [--envfile FILE] [--workdir DIR] COMMAND [ARG...]\n", argv[0]);
                 return (0);
         }
+        if (workdir != NULL && target >= 0 && pid) {
+                workdir_fd = open(workdir, O_PATH|O_DIRECTORY|O_CLOEXEC);
+                if (workdir_fd < 0)
+                        err(EXIT_FAILURE, "failed to open directory: %s", workdir);
+        }

         if (target < 0)
-                create_namespaces(user, mount, network, ipc, uts, remap_root);
+                create_namespaces(user, pid, mount, network, ipc, uts, remap_root);
         else
-                join_namespaces(target, user, mount, network, ipc, uts);
+                join_namespaces(target, user, pid, mount, network, ipc, uts);

         if (user) {
                 if (seccomp_set_filter() < 0)
@@ -410,8 +582,10 @@ main(int argc, char *argv[])
                         err(EXIT_FAILURE, "failed to load environment: %s", envfile);
         }
         if (workdir != NULL) {
-                if (chdir(workdir) < 0)
+                if ((workdir_fd >= 0 ? fchdir(workdir_fd) : chdir(workdir)) < 0)
                         err(EXIT_FAILURE, "failed to change directory: %s", workdir);
+                if (workdir_fd >= 0 && close(workdir_fd) < 0)
+                        err(EXIT_FAILURE, "failed to close directory: %s", workdir);
         }

 #ifdef ALLOW_SPECULATION
diff --git a/conf/enroot.conf.in b/conf/enroot.conf.in
index 4cdea35..1447968 100644
--- a/conf/enroot.conf.in
+++ b/conf/enroot.conf.in
@@ -27,6 +27,9 @@
 # Run containers in a new network namespace (loopback only) by default.
 #ENROOT_UNSHARE_NET         no

+# Run containers in a new PID namespace by default.
+#ENROOT_UNSHARE_PID         no
+
 # Run containers in a new IPC namespace by default.
 #ENROOT_UNSHARE_IPC         no

diff --git a/doc/cmd/start.md b/doc/cmd/start.md
index ab0a942..9d3c6e9 100644
--- a/doc/cmd/start.md
+++ b/doc/cmd/start.md
@@ -15,6 +15,7 @@ Otherwise, an interactive shell will be started within the container.
    -r, --root           Ask to be remapped to root inside the container
    -w, --rw             Make the container root filesystem writable
    -m, --mount FSTAB    Perform a mount from the host inside the container (colon-separated)
+       --pid            Run the container in a new PID namespace
        --net            Run the container in a new network namespace (loopback only)
        --ipc            Run the container in a new IPC namespace
        --uts            Run the container in a new UTS namespace
@@ -34,11 +35,12 @@ with the exception that fstab fields are colon-separated.

 The `--net` option runs the container in a new network namespace with only the loopback interface available.

+The `--pid` option runs the container in a new PID namespace. No init process is injected; the container command becomes PID 1. `SIGTERM` and `SIGINT` are forwarded to it, and it is killed if the parent `enroot` process dies.
+
 The `--ipc` option runs the container in a new IPC namespace.

 The `--uts` option runs the container in a new UTS namespace. The hostname is inherited from the host at startup; processes inside the container may change it without affecting the host.

-
 ### Configuration script

 Configuration scripts are standard bash scripts called before any containerization happened with the command and arguments of the container passed as input parameters.
@@ -108,6 +110,7 @@ Note that all changes will be stored in memory and will not persist after the co
 | `ENROOT_REMAP_ROOT` | `no` | Remap the current user to root inside containers (same as `--root`) |
 | `ENROOT_ALLOW_SUPERUSER` | `no` | Allow root to retain his superuser privileges inside containers |
 | `ENROOT_UNSHARE_NET` | `no` | Run containers in a new network namespace (same as `--net`) |
+| `ENROOT_UNSHARE_PID` | `no` | Run containers in a new PID namespace (same as `--pid`) |
 | `ENROOT_UNSHARE_IPC` | `no` | Run containers in a new IPC namespace (same as `--ipc`) |
 | `ENROOT_UNSHARE_UTS` | `no` | Run containers in a new UTS namespace (same as `--uts`) |

