diff --git a/bin/compat.h b/bin/compat.h
index ff0ec58..60ff1db 100644
--- a/bin/compat.h
+++ b/bin/compat.h
@@ -32,6 +32,45 @@
 # define compat_lastlog     lastlog
 #else

+static inline char *
+compat_unescape_ent(char *beg)
+{
+        char *dest = beg;
+        const char *src = beg;
+
+        while (*src) {
+                unsigned char cval = 0;
+                const char *val;
+
+                if (*src != '\\') {
+                        *dest++ = *src++;
+                        continue;
+                }
+                if (src[1] == '\\') {
+                        ++src;
+                        *dest++ = *src++;
+                        continue;
+                }
+                val = src + 1;
+                for (int i = 0; i < 3; ++i) {
+                        if (*val >= '0' && *val <= '7') {
+                                cval = (unsigned char)(cval << 3);
+                                cval = (unsigned char)(cval + (*val++ - '0'));
+                        } else {
+                                break;
+                        }
+                }
+                if (cval) {
+                        *dest++ = (char)cval;
+                        src = val;
+                } else {
+                        *dest++ = *src++;
+                }
+        }
+        *dest = '\0';
+        return (beg);
+}
+
