+static int
+map_file(const char *file, int prot, void **buf, size_t *len)
+{
+        int fd;
+        struct stat s;
+
+        if ((fd = open(file, O_RDONLY)) < 0)
+                goto err;
+        if (fstat(fd, &s) < 0) {
+                SAVE_ERRNO(close(fd));
+                goto err;
+        }
+        *len = (size_t)s.st_size;
+        *buf = (*len > 0) ? mmap(NULL, *len, prot, MAP_PRIVATE, fd, 0) : NULL;
+        if (*buf == MAP_FAILED) {
+                SAVE_ERRNO(close(fd));
+                goto err;
+        }
+        if (close(fd) < 0)
+                goto err;
+        return (0);
+
+ err:
+        if (*buf != MAP_FAILED && *len > 0)
+                SAVE_ERRNO(munmap(*buf, *len));
+        return (-1);
