+static void
+free_config(struct config *conf)
+{
+        struct param *p;
+
+        while (!SLIST_EMPTY(conf)) {
+                p = SLIST_FIRST(conf);
+                SLIST_REMOVE_HEAD(conf, params);
+                free(p->name);
+                free(p->value);
+                free(p);
